import{_ as t,o as a,c as n,a2 as o}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"Architecture on the Host","description":"","frontmatter":{},"headers":[],"relativePath":"self-hosting/architecture-on-host.md","filePath":"self-hosting/architecture-on-host.md"}'),r={name:"self-hosting/architecture-on-host.md"};function s(i,e,l,c,h,d){return a(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="architecture-on-the-host" tabindex="-1">Architecture on the Host <a class="header-anchor" href="#architecture-on-the-host" aria-label="Permalink to &quot;Architecture on the Host&quot;">​</a></h1><p>Everything Tragwerk runs on your VPS is <strong>generated from your <code>.tragwerk/config.xml</code></strong> and executed with Docker Compose. This page describes what that generated stack looks like on the host.</p><h2 id="from-xml-to-running-containers" tabindex="-1">From XML to running containers <a class="header-anchor" href="#from-xml-to-running-containers" aria-label="Permalink to &quot;From XML to running containers&quot;">​</a></h2><p>On each deploy, Tragwerk reads your <a href="/config/overview">configuration</a> and generates two artifacts on the server:</p><ul><li>A <strong><code>Dockerfile.{appSlug}</code></strong> per application.</li><li>A <strong><code>docker-compose.yml</code></strong> describing every container, network, and volume.</li></ul><p>It then builds the image(s) and brings up the stack — all automatically as part of a deployment.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.tragwerk/config.xml</span></span>
<span class="line"><span>        │  (generation)</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Dockerfile.{appSlug}  +  docker-compose.yml</span></span>
<span class="line"><span>        │  (docker compose build / up)</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>running containers on the VPS</span></span></code></pre></div><h2 id="application-containers" tabindex="-1">Application containers <a class="header-anchor" href="#application-containers" aria-label="Permalink to &quot;Application containers&quot;">​</a></h2><p>Each application runs as a <strong>FrankenPHP</strong> container with a security-hardened, ephemeral filesystem:</p><ul><li><strong><code>read_only</code></strong> root filesystem.</li><li><strong>tmpfs</strong> mounts for <code>/tmp</code>, <code>/data</code>, and <code>/config</code> (writable, in-memory).</li><li>A <strong>healthcheck</strong> so Compose and Traefik only route to healthy containers.</li><li>Joined to networks <strong><code>default</code></strong> and <strong><code>tragwerk-net</code></strong>.</li></ul><p>Persistent storage is provided explicitly through <a href="/config/mounts">mounts</a>, which become Docker volumes — the read-only root keeps everything else stateless.</p><div class="info custom-block"><p class="custom-block-title">Two FrankenPHP modes</p><p>By default the generated Caddyfile runs FrankenPHP in <strong>classic mode</strong> — a drop-in PHP-FPM replacement that serves each request in the traditional per-request lifecycle, so existing apps run unchanged. If the application declares <a href="/config/applications#workermode"><code>&lt;workerMode&gt;</code></a>, the Caddyfile instead emits a <code>frankenphp { worker … }</code> block that boots the front controller once and keeps it warm between requests for higher throughput.</p></div><h2 id="traefik-routing" tabindex="-1">Traefik routing <a class="header-anchor" href="#traefik-routing" aria-label="Permalink to &quot;Traefik routing&quot;">​</a></h2><p>Traefik runs at the host level (provisioned during <a href="/self-hosting/server-setup">server setup</a>) and is the single public entrypoint. The generated Compose file attaches <strong>Traefik labels</strong> to each application container to declare its hostname-based <a href="/config/routes">route</a>, and the container joins the shared external network <strong><code>tragwerk-net</code></strong> so Traefik can reach it.</p><p>Because routing is by host/subdomain, <strong>multiple applications coexist on one VPS</strong> — each answers on its own hostname while sharing the same Traefik instance and Let&#39;s Encrypt setup.</p><h3 id="why-traefik-and-not-frankenphp-s-built-in-caddy" tabindex="-1">Why Traefik and not FrankenPHP&#39;s built-in Caddy <a class="header-anchor" href="#why-traefik-and-not-frankenphp-s-built-in-caddy" aria-label="Permalink to &quot;Why Traefik and not FrankenPHP&#39;s built-in Caddy&quot;">​</a></h3><p>FrankenPHP ships with Caddy and could serve a single app directly, but Tragwerk needs to host <strong>many independent applications on the same VPS</strong>, each on its own hostname. A dedicated host-level reverse proxy in front of all app containers is the natural fit for that, so Tragwerk uses <strong>Traefik</strong> as the single public entrypoint rather than exposing each app&#39;s built-in Caddy.</p><p>Traefik also pairs well with the rest of the stack:</p><ul><li><strong>Docker-native</strong> — it discovers containers and their routes automatically from the <strong>Traefik labels</strong> on each service, with no separate routing config to maintain.</li><li><strong>Blue/green-friendly</strong> — because it watches Docker, Traefik picks up the new container and shifts traffic to it as soon as it is healthy, then drops the old one, which is exactly what the <a href="#zero-downtime-deployments">zero-downtime</a> swap relies on.</li></ul><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        Internet</span></span>
<span class="line"><span>           │</span></span>
<span class="line"><span>        Traefik  (host reverse proxy, TLS / Let&#39;s Encrypt)</span></span>
<span class="line"><span>           │   routes by hostname over tragwerk-net</span></span>
<span class="line"><span>   ┌───────┼───────────────┐</span></span>
<span class="line"><span>   ▼       ▼               ▼</span></span>
<span class="line"><span> app A   app B   ...   (FrankenPHP containers, read-only + tmpfs)</span></span></code></pre></div><h2 id="zero-downtime-deployments" tabindex="-1">Zero-downtime deployments <a class="header-anchor" href="#zero-downtime-deployments" aria-label="Permalink to &quot;Zero-downtime deployments&quot;">​</a></h2><p>Deployments aim for <strong>zero downtime</strong>: a new release should not interrupt the version that is currently serving traffic. Tragwerk uses a <strong>blue/green</strong> strategy to make this the normal case — but it cannot be <em>guaranteed</em>, since the outcome also depends on your application, your migrations, and the health of the new release (see the pitfalls below).</p><h3 id="how-blue-green-works" tabindex="-1">How blue/green works <a class="header-anchor" href="#how-blue-green-works" aria-label="Permalink to &quot;How blue/green works&quot;">​</a></h3><p>Each application runs in one of two slots, <strong>a</strong> or <strong>b</strong>. On every deploy Tragwerk targets the slot that is <em>not</em> currently live:</p><ol><li><strong>Start the new container</strong> — the freshly built image is started in the idle slot (e.g. <code>…-app-b</code>), attached to the same network as the live container (<code>…-app-a</code>). Both versions now run side by side against the same database and mounts.</li><li><strong>Run deploy hooks</strong> — the new container&#39;s entrypoint runs your <a href="/config/hooks"><code>deploy</code> hooks</a> (for example database migrations) <em>before</em> it reports healthy.</li><li><strong>Wait for health</strong> — Tragwerk polls the new container&#39;s healthcheck. If it never becomes healthy the deploy <strong>fails</strong>, the new container is discarded, and the old one keeps serving — so a broken release cannot take the site down.</li><li><strong>Switch traffic</strong> — once healthy, Traefik routes incoming requests to the new container.</li><li><strong>Remove the old container</strong> — the previous slot is stopped and removed, and the active slot is recorded for next time.</li></ol><p>Workers and the cron sidecar are <strong>not</strong> part of the swap — they are restarted separately. Pausing an environment stops the active container.</p><h3 id="database-migrations-other-pitfalls" tabindex="-1">Database migrations &amp; other pitfalls <a class="header-anchor" href="#database-migrations-other-pitfalls" aria-label="Permalink to &quot;Database migrations &amp; other pitfalls&quot;">​</a></h3><p>Because both versions run against the <strong>same database</strong> during the overlap in steps 1–4, the old code keeps serving while your migrations have already run. Plan migrations to be <strong>backward compatible</strong> with the still-running release — the expand/contract pattern:</p><ul><li><strong>Expand first.</strong> Add new columns/tables as <strong>nullable</strong> or with defaults; never rename or drop in the same deploy that introduces the new code. A dropped or renamed column breaks the old container the moment the migration runs.</li><li><strong>Contract later.</strong> Remove old columns only in a <em>subsequent</em> deploy, once no running version references them anymore.</li><li><strong>Avoid long-locking migrations.</strong> A migration that locks a large table blocks the old version&#39;s queries too; prefer online/concurrent schema changes.</li><li><strong>Migrations must be idempotent and safe to run while serving</strong> — they execute from the new container before it takes traffic, not in a maintenance window.</li><li><strong>Shared mounts</strong> are likewise written by both versions during the overlap; don&#39;t change on-disk formats incompatibly within a single deploy.</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Tragwerk runs <code>deploy</code> hooks once per deploy, from the new container, with no maintenance pause. If a migration is destructive or backward-incompatible the old version can error during the few seconds of overlap. Split such changes across two deploys (expand → switch → contract).</p></div><div class="tip custom-block"><p class="custom-block-title">Heavy or risky migrations</p><p>For data backfills or rebuilds that should not block the cutover, run them from a <a href="/config/hooks"><code>post_deploy</code> hook</a> or a one-off <a href="/config/workers">worker</a> instead of <code>deploy</code>, so the switch isn&#39;t held up waiting on them.</p></div><h2 id="sidecars-and-extra-containers" tabindex="-1">Sidecars and extra containers <a class="header-anchor" href="#sidecars-and-extra-containers" aria-label="Permalink to &quot;Sidecars and extra containers&quot;">​</a></h2><p>The generated Compose file can include additional containers around the app:</p><ul><li><strong>Services</strong> — backing services such as databases or caches run as their own sidecar containers and join <code>tragwerk-net</code>. See <a href="/config/services">Services</a>.</li><li><strong>Workers</strong> — long-running <a href="/config/workers">worker</a> processes run as separate containers that reuse the application image (read-only, healthcheck disabled).</li><li><strong>Cron</strong> — a <strong>supercronic</strong> sidecar (<code>{app}-cron</code>) runs the application&#39;s scheduled <a href="/config/crons">crons</a> from a generated crontab.</li></ul><p><a href="/config/mounts">Mounts</a> declared in the configuration are emitted as Docker volumes shared by the relevant containers.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/config/overview">Configuration Overview</a></li><li><a href="/config/routes">Routes</a></li><li><a href="/config/services">Services</a></li><li><a href="/self-hosting/server-setup">Server Setup</a></li></ul>`,37)])])}const u=t(r,[["render",s]]);export{g as __pageData,u as default};
